VALUES ('Navigating the ingress-nginx archival: why now is the time to move to Cilium', 'https://www.cncf.io/blog/2026/01/27/navigating-the-ingress-nginx-archival-why-now-is-the-time-to-move-to-cilium/', 'L''article explique pourquoi il est temps de migrer de ingress-nginx à Cilium pour le routage du trafic externe dans Kubernetes. Il détaille les avantages de Cilium et les raisons de cette transition.', 'CNCF Blog', 'PRO', 3, '["Kubernetes","ingress-nginx","Cilium","migration"]', 'Tue, 27 Jan 2026 15:00:00 +0000', '2026-02-07T23:42:17.964Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
