INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Context Engineering for Coding Agents', 'https://martinfowler.com/articles/exploring-gen-ai/context-engineering-coding-agents.html', 'L''article explore les innovations récentes en matière d''ingénierie de contexte pour les agents de codage, en se concentrant sur les fonctionnalités de configuration offertes par des outils comme Claude Code. Il met en lumière l''impact de ces avancées sur l''expérience des développeurs.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["IA","développement","outils","productivité"]', '2026-02-05T07:36:00-08:00', '2026-02-07T23:42:54.110Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments: February  4', 'https://martinfowler.com/fragments/2026-02-04.html', 'L''article partage des fragments de réflexions d''un événement organisé par Thoughtworks, notamment sur l''utilisation de l''IA en développement logiciel. Il souligne l''importance de comprendre les systèmes créés et l''utilisation de l''IA comme outil de navigation plutôt que de confiance absolue.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["IA","Développement Logiciel","Retour d''expérience"]', '2026-02-04T09:56:00-08:00', '2026-02-07T23:42:55.891Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Assessing internal quality while coding with an agent', 'https://martinfowler.com/articles/exploring-gen-ai/ccmenu-quality.html', 'Erik Doernenburg, maintainer de CCMenu, évalue l''impact d''un agent de codage sur la qualité interne du code en ajoutant une fonctionnalité et en analysant les résultats.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["IA","qualité de code","retour d''expérience"]', '2026-01-27T10:50:00-05:00', '2026-02-07T23:42:59.907Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Conversation: LLMs and the what/how loop', 'https://martinfowler.com/articles/convo-what-how.html', 'Un article sous forme de conversation entre experts sur l''utilisation des LLMs pour façonner les abstractions dans le développement logiciel. Ils discutent de la gestion du changement et de la charge cognitive, ainsi que du rôle des LLMs dans l''exploration du cycle ''what/how'' en développement.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["LLMs","abstractions","TDD","développement logiciel"]', '2026-01-21T09:40:00-05:00', '2026-02-07T23:43:04.361Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Stop Picking Sides: Manage the Tension Between Adaptation and                Optimization', 'https://martinfowler.com/articles/stop-picking-sides.html', 'L''article discute de l''importance d''équilibrer adaptation et optimisation dans les équipes, en proposant deux modes de fonctionnement : explorer (adaptation) et exploiter (optimisation). Il souligne la nécessité de gérer la tension entre ces deux approches en fonction de l''incertitude, du risque, du coût de changement et d''un seuil de preuve.', 'Martin Fowler''s blog', 'PRO', 3, '["architecture","équipes","optimisation","adaptation"]', '2026-01-13T14:59:00+00:00', '2026-02-07T23:43:06.145Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments: January  8', 'https://martinfowler.com/fragments/2026-01-08.html', 'L''article présente un rapport d''Anthropic sur l''impact de l''IA sur leur pratique de développement logiciel, avec des gains de productivité significatifs. Il met également en lumière un cas d''utilisation concret par Obie Fernandez, qui a développé un système de distillation de connaissances en utilisant Claude, prêt pour la production.', 'Martin Fowler''s blog', 'LES_DEUX', 4, '["IA","développement logiciel","productivité","retour d''expérience"]', '2026-01-08T08:29:00-05:00', '2026-02-07T23:43:10.243Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments: December 16', 'https://martinfowler.com/fragments/2025-12-16.html', 'Un guide illustré sur la modernisation des mainframes et une opinion sur les outils de revue de code pour le code généré par l''IA.', 'Martin Fowler''s blog', 'PRO', 3, '["mainframe","modernisation","IA","code review"]', '2025-12-16T10:14:00-05:00', '2026-02-07T23:43:12.135Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments Dec 4', 'https://martinfowler.com/articles/20251204-frags.html', 'Un article résumant une étude de Carnegie Mellon sur l''impact de l''IA sur des projets open-source, montrant une dégradation de la qualité du code. Il aborde aussi l''histoire inspirante de Jim Highsmith utilisant l''IA pour lutter contre la maladie de Parkinson.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["IA","open-source","qualité du code","retour d''expérience"]', '2025-12-04T10:59:00-05:00', '2026-02-07T23:43:18.059Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('My Foreword to "Frictionless"', 'https://martinfowler.com/articles/frictionless-foreword.html', 'Martin Fowler recommande le livre ''Frictionless'' de Nicole Forsgren et Abi Noda sur la productivité logicielle, qu''il a trouvé suffisamment pertinent pour écrire une préface.', 'Martin Fowler''s blog', 'PRO', 3, '["productivité","livre","recommandation"]', '2025-11-18T12:19:00-05:00', '2026-02-07T23:43:21.954Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('The Learning Loop and LLMs', 'https://martinfowler.com/articles/llm-learning-loop.html', 'L''article explore l''utilisation des modèles de langage (LLMs) comme outils utiles, mais met en garde contre leur utilisation pour contourner le processus d''apprentissage essentiel dans la pratique professionnelle.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["LLMs","apprentissage","bonnes pratiques"]', '2025-11-04T09:14:00-05:00', '2026-02-07T23:43:24.133Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments Nov 3', 'https://martinfowler.com/articles/2025-11-03-frags.html', 'L''article discute des dangers de sécurité des navigateurs équipés de LLM et des opinions divergentes sur l''aide à la programmation par IA. Il souligne l''importance de l''expérience pour utiliser efficacement ces outils.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["IA","sécurité","développement","bonnes pratiques"]', '2025-11-03T19:42:00-05:00', '2026-02-07T23:43:26.190Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Agentic AI and Security', 'https://martinfowler.com/articles/agentic-ai-security.html', 'L''article explore les risques de sécurité des systèmes d''IA agentic, notamment à travers le concept de ''Lethal Trifecta''. Il propose des solutions pour atténuer ces risques en décomposant les tâches complexes.', 'Martin Fowler''s blog', 'PRO', 3, '["IA","sécurité","architecture"]', '2025-10-28T09:20:00-04:00', '2026-02-07T23:43:28.033Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Fragments and Links', 'https://martinfowler.com/articles/20251021-frags.html', 'Mathias Verraes discute de la relation entre les Domaines et les Contextes Délimités dans la conception pilotée par le domaine, soulignant que leur relation n''est pas toujours 1:1. Gary Marcus plaide pour des outils d''IA spécialisés plutôt que des solutions universelles. Matt Bracken raconte l''histoire de Direct File, un système de déclaration de revenus électronique qui a été annulé.', 'Martin Fowler''s blog', 'PRO', 3, '["Domain-Driven Design","IA","Gouvernement"]', '2025-10-21T11:02:00-04:00', '2026-02-07T23:43:30.431Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Understanding Spec-Driven-Development: Kiro, spec-kit, and Tessl', 'https://martinfowler.com/articles/exploring-gen-ai/sdd-3-tools.html', 'L''article explore le concept de Spec-Driven Development (SDD) et analyse trois outils (Kiro, spec-kit, Tessl) qui se revendiquent comme des outils SDD. L''auteure tente de démêler ce que signifie le SDD actuellement.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["AI","Spec-Driven Development","Outils"]', '2025-10-15T08:33:00-04:00', '2026-02-07T23:43:32.118Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Anchoring AI to a reference application', 'https://martinfowler.com/articles/exploring-gen-ai/anchoring-to-reference.html', 'L''article explore comment l''IA générative peut aider à maintenir à jour les modèles de service dans les organisations, en facilitant la mise à jour des services existants avec les dernières normes et pratiques de codage.', 'Martin Fowler''s blog', 'PRO', 3, '["IA générative","architecture","DevOps"]', '2025-09-25T12:57:00+03:00', '2026-02-07T23:43:34.329Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('To vibe or not to vibe', 'https://martinfowler.com/articles/exploring-gen-ai/to-vibe-or-not-vibe.html', 'L''article explore le concept de ''vibe coding'' et propose une évaluation des risques basée sur trois dimensions : probabilité, impact et détectabilité. Il s''agit d''une analyse pertinente pour comprendre quand utiliser cette approche.', 'Martin Fowler''s blog', 'LES_DEUX', 3, '["vibe coding","risk assessment","best practices"]', '2025-09-23T10:53:00+03:00', '2026-02-07T23:43:35.916Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('From Black Box to Blueprint', 'https://martinfowler.com/articles/black-box-to-blueprint.html', 'L''article décrit une approche pour transformer des systèmes hérités opaques en architectures documentées grâce à l''ingénierie inverse assistée par l''IA. Une méthode multi-lens est utilisée pour reconstruire les spécifications fonctionnelles à partir d''éléments UI, de binaires et de lignées de données.', 'Martin Fowler''s blog', 'PRO', 4, '["architecture","legacy systems","reverse engineering","AI","modernization"]', '2025-08-28T07:24:00-04:00', '2026-02-07T23:43:40.071Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Research, Review, Rebuild: Intelligent Modernisation with MCP and Strategic Prompting', 'https://martinfowler.com/articles/research-review-rebuild.html', 'L''article décrit la modernisation du système de gestion hospitalière open-source Bahmni, passant d''AngularJS à React + TypeScript et d''une API OpenMRS REST à une API HL7 FHIR. L''auteur utilise une méthodologie structurée de recherche, revue et reconstruction avec des outils comme Cline, Claude 3.5 Sonnet, et Atlassian MCP pour accélérer le processus.', 'Martin Fowler''s blog', 'LES_DEUX', 4, '["React","TypeScript","Modernisation","API","Retour d''expérience"]', '2025-08-27T10:15:00-04:00', '2026-02-07T23:43:42.421Z');

