VALUES ('We Spent Days Fighting a Zebra Card Printer. So You Don''t Have To.', 'https://dev.to/alex_purpleowl/we-spent-days-fighting-a-zebra-card-printer-so-you-dont-have-to-3hg', 'Un développeur partage son expérience douloureuse avec l''imprimante Zebra ZC350 et son encodeur NFC, puis propose une solution open-source en .NET 8 appelée Dazzle pour simplifier l''automatisation des cartes. L''outil agit comme un pont entre l''application et le matériel via JSON.', 'dev.to', 'PRO', 4, '["C#",".NET 8","hardware","open-source","automatisation","Zebra","NFC"]', 'Thu, 26 Mar 2026 20:09:07 +0000', '2026-03-26T20:29:04.597Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('How To Prevent Website Downtime', 'https://dev.to/vincentbean/how-to-prevent-website-downtime-1i6l', 'L''article explique les causes courantes des temps d''arrêt des sites web (infrastructure, bugs, configuration) et propose des solutions pour les prévenir via une meilleure architecture, des environnements multiples et une surveillance efficace. Il détaille aussi comment le trafic atteint un site et les points de défaillance potentiels.', 'dev.to', 'PRO', 3, '["architecture","sécurité","DevOps","monitoring","disponibilité","bonnes pratiques"]', 'Thu, 26 Mar 2026 19:59:00 +0000', '2026-03-26T20:29:10.269Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Prevent agentic identity theft', 'https://stackoverflow.blog/2026/03/27/prevent-agentic-identity-theft/', 'L''article aborde les risques de vol d''identité d''agents IA dans les entreprises, avec un focus sur la gouvernance des identifiants via une architecture zero-knowledge. Nancy Wang (CTO de 1Password) explique comment sécuriser les agents locaux et gérer les intentions malveillantes dans un contexte d''intégration croissante des agents IA.', 'StackOverflow Blog', 'PRO', 3, '["sécurité","IA agents","architecture zero-knowledge","gestion des identifiants","bonnes pratiques entreprise"]', 'Fri, 27 Mar 2026 07:40:00 GMT', '2026-03-27T18:30:35.921Z');

