VALUES ('The weight of AI models: Why infrastructure always arrives slowly', 'https://www.cncf.io/blog/2026/03/27/the-weight-of-ai-models-why-infrastructure-always-arrives-slowly/', 'L''article aborde un défi critique et souvent sous-estimé dans l''adoption de l''IA : la gestion et la distribution à grande échelle des fichiers de poids des modèles d''IA, qui deviennent rapidement volumineux et complexes à gérer.', 'CNCF Blog', 'PRO', 3, '["IA","infrastructure","DevOps","scalabilité","gestion de modèles"]', 'Fri, 27 Mar 2026 11:00:00 +0000', '2026-03-27T18:31:24.882Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Como eu penso e escrevo meus testes', 'https://dev.to/ewertoncodes/como-eu-penso-e-escrevo-meus-testes-4j26', 'L''article explique l''importance des tests unitaires, d''intégration et de bout en bout dans le développement logiciel, en insistant sur leur organisation via la pyramide des tests. Il présente aussi le TDD (Test-Driven Development) comme méthode de conception, avec un flux en 4 étapes et une structure de test en 3 parties (setup, action, vérification).', 'dev.to', 'PRO', 3, '["tests","TDD","pyramide des tests","bonnes pratiques","architecture logicielle"]', 'Fri, 27 Mar 2026 18:19:51 +0000', '2026-03-27T18:32:03.910Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('How to compare team capacity before committing to a software deadline', 'https://dev.to/oscarcaldera/how-to-compare-team-capacity-before-committing-to-a-software-deadline-1ho6', 'L''article démystifie l''idée que ajouter des développeurs réduit les délais de livraison, expliquant que le travail reste le même et que les étapes restent séquentielles. Il met en avant que les différentes configurations d''équipe impactent surtout les risques d''exécution, l''oisiveté, la charge de travail et les goulots d''étranglement, sans forcément changer la date de livraison finale.', 'dev.to', 'PRO', 4, '["gestion de projet","équipes","délais","bottlenecks","coordination"]', 'Fri, 27 Mar 2026 18:10:49 +0000', '2026-03-27T18:32:14.296Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('GCC vs Clang: Same Instructions, Different Performance (AGU Insight)', 'https://dev.to/aabhinavg/gcc-vs-clang-same-instructions-different-performance-agu-insight-1pae', 'L''article compare les performances de GCC et Clang sur un benchmark simple, révélant que GCC utilise moins de cycles CPU malgré des instructions similaires. La différence vient de la gestion des calculs d''adresses (AGU), de l''ordonnancement des instructions et de la latence cachée, où GCC optimise mieux ces aspects.', 'dev.to', 'PRO', 4, '["compilateurs","performance","C/C++","optimisation","GCC","Clang","AGU","x86"]', 'Fri, 27 Mar 2026 18:01:58 +0000', '2026-03-27T18:32:20.428Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('Supply Chain Attacks on Developers: Lessons from LiteLLM and Trivy', 'https://dev.to/pooyagolchian/supply-chain-attacks-on-developers-lessons-from-litellm-and-trivy-1ocg', 'Deux attaques majeures par supply chain en 2026 ont ciblé des outils de développement (LiteLLM et Trivy), compromettant des milliers de projets via des mécanismes de vol de credentials et de backdoors. Les attaques exploitaient des vulnérabilités dans les dépendances et les workflows CI/CD.', 'dev.to', 'PRO', 4, '["sécurité","supply-chain","CI/CD","bonnes-pratiques","outils-de-développement"]', 'Fri, 27 Mar 2026 18:01:51 +0000', '2026-03-27T18:32:21.679Z');

INSERT OR IGNORE INTO articles (titre, url, resume, source, categorie_mistral, score_mistral, tags, date_article, date_collecte)
VALUES ('How to Deploy an AI Agent to Production: VPS, Docker &amp; Serverless (2026)', 'https://dev.to/paxrel/how-to-deploy-an-ai-agent-to-production-vps-docker-amp-serverless-2026-4p9i', 'L''article propose trois méthodes pour déployer un agent IA en production (VPS, Docker, serverless) avec des configurations concrètes, des coûts détaillés et des conseils de monitoring. Il compare les approches en fonction des besoins (24/7, multi-agents, event-triggered) et inclut des recommandations de fournisseurs VPS.', 'dev.to', 'PRO', 4, '["déploiement","IA","Docker","VPS","serverless","production","monitoring","coûts"]', 'Fri, 27 Mar 2026 18:01:22 +0000', '2026-03-27T18:32:24.486Z');